        scanf("%d", &voti[i]);
    }
    printf("Elemento da cercare: ");
    scanf("%d", &cercato);
    pos = cerca(voti, N, cercato);
    if (pos != -1)
        printf("Trovato alla posizione %d\n", pos);
    else
        printf("Non trovato\n");
    return 0;
}

