13.10.10 Esercizio 10: Massimo con puntatore
Scrivi int massimo(int v[], int n) usando un puntatore.
Soluzione:
#include &lt;stdio.h&gt;

int massimo(int v[], int n) {
    int *p = v;
    int max = *p;
    int i;

    for (i = 0; i &lt; n; i++) {
        if (*p &gt; max)
            max = *p;
        p++;
    }

    return max;
}

int main() {
    int v[5] = {3, 7, 2, 9, 5};
    printf("%d\n", massimo(v, 5));
    return 0;
}


13.10.11 Esercizio 11: Restituire un puntatore
Scrivi int* trovaPari(int v[], int n) che restituisce il puntatore al primo elemento pari, NULL se non esiste.
Soluzione:
#include &lt;stdio.h&gt;

int* trovaPari(int v[], int n) {
    int *p = v;
    int i;

    for (i = 0; i &lt; n; i++) {
        if (*p % 2 == 0)
            return p;
        p++;
    }

    return NULL;
}

int main() {
    int v[5] = {1, 3, 5, 8, 9};
    int *ris = trovaPari(v, 5);

    if (ris != NULL)
        printf("%d\n", *ris);
    else
        printf("Nessun pari\n");

    return 0;
}

